  const [textRef, textOff] = useParallax(0.12);
  const go = (p) => { navigate(p); window.scrollTo({ top: 0 }); };

  return (
    <div className="hiw">

      {/* ── Hero ── */}
      <section className="hiw-hero">
        <div ref={bgRef} className="hiw-hero__bg"
          style={{ transform: `translateY(${bgOff}px) scale(1.15)` }} />
        <div className="hiw-hero__ov" />
        <div className="hiw-hero__grid" />
        {/* Bleed moves counter to scroll */}
        <div ref={bleedRef} className="hiw-hero__bleed"
          style={{ transform: `translate(-50%,-50%) translateY(${blOff}px)` }}>HOW</div>
        {/* Hero text at medium parallax speed */}
        <div ref={textRef} className="hiw-hero__content"
          style={{ transform: `translateY(${textOff}px)` }}>
          <div className="eyebrow" data-reveal="fade">The Process</div>
          <h1 className="hiw-hero__h1" data-reveal="up" data-reveal-delay="100">
